#!/usr/bin/env node
/**
 * Originals discoverability sync-check.
 *
 * src/lib/originals-directory.ts (the ORIGINALS array) is the source of truth for
 * every /originals article. This verifies the HAND-MAINTAINED surfaces that can
 * silently drift from it:
 *   - src/app/originals/<slug>/page.tsx   (the page must exist; no orphan pages)
 *   - src/app/sitemap.ts                  (each article URL is hand-listed)
 *   - public/llms.txt                     (the originals block plus its "(N articles)" count)
 *
 * originals.xml and llms-full.txt are GENERATED by the prebuild (scripts/fetch-feeds.ts
 * and scripts/generate-llms-full.ts) and regenerate on every build, so they self-heal
 * and are intentionally out of scope here.
 *
 * Exit code: 0 if every surface matches the directory, 1 if anything drifts, so it can
 * gate a CI step or be run before pushing article changes. Reports exactly what is
 * missing or orphaned.
 *
 * Usage:
 *   node scripts/check-originals-sync.mjs
 */

import fs from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, '..');
const at = (...parts) => path.join(REPO_ROOT, ...parts);
const read = (rel) => fs.readFile(at(rel), 'utf-8');
const uniqueSorted = (arr) => [...new Set(arr)].sort();

async function main() {
  // Source of truth: every quoted slug in the ORIGINALS array. The interface field
  // `slug: string;` is unquoted, so it is never matched.
  const dirSrc = await read('src/lib/originals-directory.ts');
  const slugs = uniqueSorted([...dirSrc.matchAll(/slug:\s*'([^']+)'/g)].map((m) => m[1]));
  const slugSet = new Set(slugs);

  const problems = []; // [label, items[]]
  const passed = []; // human summary lines

  // 1) Pages on disk, both directions.
  const originalsDir = at('src/app/originals');
  const dirents = await fs.readdir(originalsDir, { withFileTypes: true });
  const pageSlugs = [];
  for (const e of dirents) {
    if (!e.isDirectory()) continue;
    try {
      await fs.access(path.join(originalsDir, e.name, 'page.tsx'));
      pageSlugs.push(e.name);
    } catch {
      // a subdirectory without page.tsx is not an article; skip it
    }
  }
  const pageSet = new Set(pageSlugs);
  const missingPages = slugs.filter((s) => !pageSet.has(s));
  const orphanPages = pageSlugs.filter((s) => !slugSet.has(s)).sort();
  if (missingPages.length) problems.push(['page.tsx MISSING (in directory, no page file)', missingPages]);
  if (orphanPages.length) problems.push(['page.tsx ORPHAN (page file exists, not in directory)', orphanPages]);
  if (!missingPages.length && !orphanPages.length) passed.push(`pages: ${slugs.length} match`);

  // 2) sitemap.ts (hand-listed per article). The file is machine-clean, so the reverse
  //    check is safe. Slugs are terminated by a backtick in the URL template.
  const sitemap = await read('src/app/sitemap.ts');
  const missingSitemap = slugs.filter((s) => !sitemap.includes('originals/' + s + '`'));
  const sitemapSlugs = uniqueSorted([...sitemap.matchAll(/originals\/([a-z0-9-]+)`/g)].map((m) => m[1]));
  const orphanSitemap = sitemapSlugs.filter((s) => !slugSet.has(s));
  if (missingSitemap.length) problems.push(['sitemap.ts MISSING', missingSitemap]);
  if (orphanSitemap.length) problems.push(['sitemap.ts ORPHAN (URL not in directory)', orphanSitemap]);
  if (!missingSitemap.length && !orphanSitemap.length) passed.push(`sitemap.ts: ${slugs.length} match`);

  // 3) llms.txt originals block plus the "(N articles)" count. Forward and count only:
  //    llms.txt also names article slugs in prose (companion-editorial links), so a
  //    reverse check would be noisy. In the article list each slug is followed by ")".
  const llms = await read('public/llms.txt');
  const missingLlms = slugs.filter((s) => !llms.includes('originals/' + s + ')'));
  if (missingLlms.length) problems.push(['llms.txt MISSING from originals block', missingLlms]);
  const countMatch = llms.match(/Original editorial articles by TensorFeed \((\d+) articles\)/);
  const llmsCount = countMatch ? Number(countMatch[1]) : null;
  if (llmsCount === null) {
    problems.push(['llms.txt COUNT header not found', ['expected "(N articles)"']]);
  } else if (llmsCount !== slugs.length) {
    problems.push(['llms.txt COUNT mismatch', [`header says ${llmsCount}, directory has ${slugs.length}`]]);
  }
  if (!missingLlms.length && llmsCount === slugs.length) passed.push(`llms.txt: ${slugs.length} match plus count`);

  // 4) Retired bylines. "Ripper" is a retired persona (Evan's old byline; he stepped off
  //    the page to run the backend, and Adrian Vale inherited the writing seat). The
  //    daily-article skill bans it, but an automated run can still fall back to it (a
  //    generation pass once wrote the git user.name "Ripper" instead of rotating), so this
  //    hard-gates it: no article's canonical byline may be a retired name. Checks the two
  //    machine-parseable positions per article, the directory `author:` field and the
  //    page's <ArticleJsonLd author="..."> prop, which is enough to fail a PR before
  //    auto-merge. Add names here as personas retire.
  const RETIRED_BYLINES = new Set(['Ripper']);
  const dirAuthors = [...dirSrc.matchAll(/author:\s*'([^']+)'/g)].map((m) => m[1]);
  const retiredInDir = uniqueSorted(dirAuthors.filter((a) => RETIRED_BYLINES.has(a)));
  const retiredInPages = [];
  for (const slug of pageSlugs) {
    const page = await read('src/app/originals/' + slug + '/page.tsx');
    for (const m of page.matchAll(/author=["']([^"']+)["']/g)) {
      if (RETIRED_BYLINES.has(m[1])) { retiredInPages.push(slug); break; }
    }
  }
  if (retiredInDir.length) problems.push(['directory RETIRED byline (author is a retired persona)', retiredInDir]);
  if (retiredInPages.length) problems.push(['page.tsx RETIRED byline (ArticleJsonLd author is a retired persona)', uniqueSorted(retiredInPages)]);
  if (!retiredInDir.length && !retiredInPages.length) passed.push(`bylines: no retired names (${[...RETIRED_BYLINES].join(', ')} guarded)`);

  // 5) OG social-card shim per article. Each originals route needs an opengraph-image.tsx
  //    (generated by scripts/generate-og-shims.ts) or its link previews render no image.
  //    The generator is idempotent; run `npx tsx scripts/generate-og-shims.ts` to mint any
  //    that are missing. Enforced across every article since the backfill made it 165/165.
  const missingShim = [];
  for (const slug of slugs) {
    try {
      await fs.access(path.join(originalsDir, slug, 'opengraph-image.tsx'));
    } catch {
      missingShim.push(slug);
    }
  }
  if (missingShim.length) problems.push(['opengraph-image.tsx MISSING (run scripts/generate-og-shims.ts)', missingShim]);
  else passed.push(`OG shims: ${slugs.length} present`);

  // 6) Hero on the newest article. 74 legacy articles predate the ArticleHero convention,
  //    so a blanket hero gate is not yet possible; instead guard the freshest cadence
  //    output, the TOP entry of the ORIGINALS array (added newest-first), which is the one
  //    a daily run just wrote. Graphic-mode hero needs no image asset, so "has a hero" is
  //    always achievable. A page "has a hero" if it renders <ArticleHero.
  const orderedSlugs = [...dirSrc.matchAll(/slug:\s*'([^']+)'/g)].map((m) => m[1]);
  const newestSlug = orderedSlugs[0];
  if (newestSlug && pageSet.has(newestSlug)) {
    const newestPage = await read('src/app/originals/' + newestSlug + '/page.tsx');
    if (!newestPage.includes('<ArticleHero')) {
      problems.push(['newest article MISSING hero (add <ArticleHero>)', [newestSlug]]);
    } else {
      passed.push(`hero: newest article (${newestSlug}) has one`);
    }
  }

  const out = [];
  out.push(`Originals sync-check  (source of truth: ${slugs.length} articles in originals-directory.ts)`);
  out.push('');

  if (problems.length === 0) {
    for (const line of passed) out.push(`  OK  ${line}`);
    out.push('');
    out.push('All hand-maintained surfaces are in sync. (originals.xml and llms-full.txt regenerate on build.)');
    console.log(out.join('\n'));
    process.exit(0);
  }

  out.push('DRIFT DETECTED:');
  out.push('');
  for (const [label, items] of problems) {
    out.push(`  ${label} (${items.length}):`);
    for (const it of items) out.push(`    - ${it}`);
    out.push('');
  }
  for (const line of passed) out.push(`  OK  ${line}`);
  out.push('');
  out.push('Update the surface(s) above to match originals-directory.ts, then re-run.');
  console.error(out.join('\n'));
  process.exit(1);
}

main().catch((err) => {
  console.error('check-originals-sync failed:', err);
  process.exit(1);
});
